set.code:
mkdir -p project/{src,test,docs}
echo file{1..5}.txt
cp config.yml{,.bak}
ls project/

ACTION="${1:-help}"
case "$ACTION" in
  start)  echo 'Starting service...';;
  stop)   echo 'Stopping service...';;
  *)      echo "Usage: $0 {start|stop}";;
esac

greet() {
  echo "Hello, $1! Today is $(date +%A)."
}
greet 'admin'
greet 'developer'

log() {
  printf '[%s] %s\n' "$(date +%T)" "$*"
}
log 'Deploy started'
log 'Pulling latest image'

is_port_open() {
  ss -tln | grep -q ":$1 " && return 0 || return 1
}
is_port_open 22 && echo 'SSH open' || echo 'SSH closed'

outer() {
  local secret='hidden'
  echo "Inside: $secret"
}
outer
echo "Outside: ${secret:-not visible}"

deploy() {
  local env="$1" tag="$2"
  echo "Deploying $tag to $env"
}
deploy production v2.1.0
deploy staging v2.2.0-rc1

#!/usr/bin/env bash
die()  { echo "ERROR: $*" >&2; exit 1; }
info() { echo "INFO: $*"; }
info 'Library loaded'
[ -f config.yml ] || die 'Missing config'
